import{_ as r,c as i,o as t,ae as l}from"./chunks/framework.DI6M9D4h.js";const g=JSON.parse('{"title":"MiCDN - 轻量级 CDN 服务器","description":"","frontmatter":{},"headers":[],"relativePath":"micdn/index.md","filePath":"micdn/index.md"}'),e={name:"micdn/index.md"};function n(o,a,s,h,d,u){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="micdn-轻量级-cdn-服务器" tabindex="-1">MiCDN - 轻量级 CDN 服务器 <a class="header-anchor" href="#micdn-轻量级-cdn-服务器" aria-label="Permalink to &quot;MiCDN - 轻量级 CDN 服务器&quot;">​</a></h1><h2 id="产品定位" tabindex="-1">产品定位 <a class="header-anchor" href="#产品定位" aria-label="Permalink to &quot;产品定位&quot;">​</a></h2><p>MiCDN 是一个<strong>轻量级的 CDN 服务器</strong>，专为局域网环境和内部项目集群设计，提供高效、可靠的资源分发和文件服务。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="📦-包管理镜像" tabindex="-1">📦 包管理镜像 <a class="header-anchor" href="#📦-包管理镜像" aria-label="Permalink to &quot;📦 包管理镜像&quot;">​</a></h3><ul><li><strong>Maven 镜像</strong>：缓存和加速 Maven 依赖下载</li><li><strong>NPM 镜像</strong>：缓存和加速 NPM 包下载</li></ul><h3 id="🗂️-静态文件服务" tabindex="-1">🗂️ 静态文件服务 <a class="header-anchor" href="#🗂️-静态文件服务" aria-label="Permalink to &quot;🗂️ 静态文件服务&quot;">​</a></h3><ul><li><strong>静态资源托管</strong>：提供静态文件的 HTTP 访问</li><li><strong>资源版本管理</strong>：支持不同版本的静态资源</li></ul><h3 id="📤-文件存储服务" tabindex="-1">📤 文件存储服务 <a class="header-anchor" href="#📤-文件存储服务" aria-label="Permalink to &quot;📤 文件存储服务&quot;">​</a></h3><ul><li><strong>文件上传/下载</strong>：简单的文件托管功能</li><li><strong>Blob 存储</strong>：对象存储服务，支持文件管理</li></ul><h3 id="🌐-局域网分发" tabindex="-1">🌐 局域网分发 <a class="header-anchor" href="#🌐-局域网分发" aria-label="Permalink to &quot;🌐 局域网分发&quot;">​</a></h3><ul><li><strong>局域网内分发</strong>：在内部网络中快速分发资源</li><li><strong>离线环境支持</strong>：适合网络隔离的环境</li></ul><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to &quot;应用场景&quot;">​</a></h2><h3 id="企业内部环境" tabindex="-1">企业内部环境 <a class="header-anchor" href="#企业内部环境" aria-label="Permalink to &quot;企业内部环境&quot;">​</a></h3><ul><li><strong>产品分发</strong>：在产品线内部分发构建产物和安装包</li><li><strong>静态文件服务</strong>：托管前端静态资源、文档等</li><li><strong>私有仓库</strong>：作为 Maven/NPM 的本地镜像，加速依赖下载</li><li><strong>对象存储</strong>：轻量级的文件存储解决方案</li></ul><h3 id="开发测试环境" tabindex="-1">开发测试环境 <a class="header-anchor" href="#开发测试环境" aria-label="Permalink to &quot;开发测试环境&quot;">​</a></h3><ul><li><strong>本地镜像</strong>：加速开发过程中的依赖下载</li><li><strong>资源共享</strong>：团队内部共享开发资源</li><li><strong>持续集成</strong>：CI/CD 流程中的资源存储</li></ul><h2 id="技术特点" tabindex="-1">技术特点 <a class="header-anchor" href="#技术特点" aria-label="Permalink to &quot;技术特点&quot;">​</a></h2><ul><li><strong>轻量级</strong>：占用资源少，部署简单</li><li><strong>无数据库依赖</strong>：使用文件系统存储，无需配置数据库</li><li><strong>Linux 专用</strong>：专为 Linux 系统优化，不支持 Windows</li><li><strong>易于集成</strong>：可与现有系统无缝集成</li><li><strong>高性能</strong>：高效的文件服务和缓存机制</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ul><li><a href="/micdn/install.html">安装指南</a>：详细的安装步骤</li><li><a href="/micdn/build.html">编译文档</a>：从源码构建 MiCDN</li></ul><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to &quot;项目地址&quot;">​</a></h2><p><a href="https://github.com/beangle/micdn" target="_blank" rel="noreferrer">GitHub 仓库</a></p>',23)])])}const m=r(e,[["render",n]]);export{g as __pageData,m as default};
